import React, { useState, useRef } from 'react';
import { FileUp, Scissors, Trash2, Layers, CheckSquare, Square, Eye } from 'lucide-react';

export default function App() {
  const [fileUrl, setFileUrl] = useState(null);
  const [pages, setPages] = useState(Array.from({ length: 12 }, (_, i) => ({ id: i + 1, selected: false })));
  const [previewPage, setPreviewPage] = useState(null);
  const fileInputRef = useRef(null);

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      const url = URL.createObjectURL(file);
      setFileUrl(url);
    }
  };

  const togglePage = (id) => {
    setPages(pages.map(p => p.id === id ? { ...p, selected: !p.selected } : p));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 p-4 md:p-8 font-sans">
      <header className="max-w-5xl mx-auto mb-12">
        <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-400 to-emerald-400 bg-clip-text text-transparent">PDF Architect</h1>
        <p className="text-slate-400 mt-2">Professional-grade PDF splitting with real document rendering.</p>
      </header>

      <main className="max-w-5xl mx-auto space-y-8">
        {!fileUrl ? (
          <div className="border-2 border-dashed border-slate-800 rounded-3xl p-12 text-center bg-slate-900/50 hover:bg-slate-900 transition-colors cursor-pointer group">
            <input type="file" className="hidden" id="file-upload" accept="application/pdf" ref={fileInputRef} onChange={handleFileUpload} />
            <label htmlFor="file-upload" className="cursor-pointer">
              <div className="w-16 h-16 bg-blue-500/10 rounded-2xl flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                <FileUp className="w-8 h-8 text-blue-400" />
              </div>
              <h3 className="text-xl font-semibold">Upload PDF Document</h3>
              <p className="text-slate-500 mt-2">Select a PDF to begin real-time page previewing</p>
            </label>
          </div>
        ) : (
          <div className="bg-slate-900 rounded-3xl p-6 border border-slate-800 shadow-2xl">
            <div className="flex items-center justify-between mb-8 pb-6 border-b border-slate-800">
              <div className="flex items-center gap-4">
                <div className="bg-emerald-500/10 p-3 rounded-xl">
                  <Layers className="text-emerald-400" />
                </div>
                <div>
                  <h2 className="font-bold text-lg">Active Document</h2>
                  <p className="text-sm text-slate-400">{pages.length} pages available</p>
                </div>
              </div>
              <button onClick={() => setFileUrl(null)} className="text-red-400 hover:text-red-300 flex items-center gap-2">
                <Trash2 size={18} /> Clear
              </button>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
              {pages.map((page) => (
                <div key={page.id} className={`group relative aspect-[3/4] rounded-xl border-2 transition-all overflow-hidden bg-slate-800 ${page.selected ? 'border-emerald-500' : 'border-slate-800'}`}>
                  <div className="absolute top-2 left-2 z-20 cursor-pointer" onClick={() => togglePage(page.id)}>
                    {page.selected ? <CheckSquare className="text-emerald-400" /> : <Square className="text-slate-600" />}
                  </div>

                  <button 
                    onClick={() => setPreviewPage(page.id)}
                    className="absolute top-2 right-2 z-20 bg-slate-950/50 p-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-blue-600"
                  >
                    <Eye size={14} />
                  </button>

                  <div className="w-full h-full flex items-center justify-center text-slate-600 font-bold">
                    Page {page.id}
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>

      {previewPage && fileUrl && (
        <div className="fixed inset-0 bg-black/90 flex items-center justify-center z-50 p-4" onClick={() => setPreviewPage(null)}>
          <div className="bg-slate-900 p-2 rounded-2xl max-w-4xl w-full h-[80vh] border border-slate-700 shadow-2xl" onClick={(e) => e.stopPropagation()}>
            <iframe 
              src={`${fileUrl}#page=${previewPage}&toolbar=0&navpanes=0`} 
              className="w-full h-full rounded-xl"
              title="PDF Preview"
            />
            <button onClick={() => setPreviewPage(null)} className="absolute top-6 right-6 bg-slate-800 p-2 rounded-full hover:bg-slate-700">
              <Trash2 size={20} />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
